+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { isRelation } from '../relation/utils/is-relation';
+import { addTrait, getTrait, hasTrait, removeTrait, setTrait } from '../trait/trait';
+import type { ConfigurableTrait, Trait, TraitRecord } from '../trait/types';
+import { getEntityWorld } from '../entity/entity';
+
+export const $aspect = Symbol('aspect');
+let aspectId = 0;
+
+type UnionToIntersection<U> = (U extends unknown ? (x: U) => 0 : never) extends (x: infer I) => 0
+    ? I
+    : never;
+export type AspectRecord<T extends readonly Trait[]> = UnionToIntersection<TraitRecord<T[number]>>;
+
+export type Aspect<T extends readonly Trait[] = readonly Trait[]> = {
+    readonly id: number;
+    readonly traits: T;
+    readonly schema: AspectRecord<T>;
+    readonly [$aspect]: true;
+};
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+export function createAspect<const T extends readonly (Trait | Aspect)[]>(...inputs: T): Aspect {
+    if (inputs.length < 2) throw new Error('createAspect requires at least two traits');
+    const traits = inputs.flatMap((input) => (isAspect(input) ? input.traits : [input])) as Trait[];
+    const fields = new Set<string>();
+    for (const trait of traits) {
+        if (isRelation(trait[$internal].relation)) throw new Error('Relations cannot be aspect constituents');
+        for (const field of Object.keys(trait.schema)) {
+            if (fields.has(field)) throw new Error(`Aspect traits cannot share field "${field}"`);
+            fields.add(field);
+        }
+    }
+    return Object.freeze({ id: aspectId++, traits: Object.freeze(traits), schema: Object.freeze({}), [$aspect]: true }) as Aspect;
+}
+
+export function hasAspect(entity: Entity, aspect: Aspect) {
+    const world = getEntityWorld(entity);
+    return aspect.traits.every((trait) => hasTrait(world, entity, trait));
+}
+
+export function getAspect(entity: Entity, aspect: Aspect) {
+    if (!hasAspect(entity, aspect)) return undefined;
+    const world = getEntityWorld(entity);
+    return Object.assign({}, ...aspect.traits.map((trait) => getTrait(world, entity, trait)));
+}
+
+function valuesFor(aspect: Aspect, value: Record<string, any>) {
+    return aspect.traits.map((trait) => {
+        const fields = Object.keys(trait.schema);
+        return [trait, Object.fromEntries(fields.filter((field) => field in value).map((field) => [field, value[field]]))] as const;
+    });
+}
+
+export function setAspect(entity: Entity, aspect: Aspect, value: Record<string, any>, triggerChanged = true) {
+    const world = getEntityWorld(entity);
+    for (const [trait, partial] of valuesFor(aspect, value)) {
+        if (Object.keys(partial).length) setTrait(world, entity, trait, partial, triggerChanged);
+    }
+}
+
+export function addAspect(entity: Entity, aspect: Aspect, value: Record<string, any> = {}) {
+    const world = getEntityWorld(entity);
+    for (const [trait, partial] of valuesFor(aspect, value)) {
+        if (!hasTrait(world, entity, trait)) addTrait(world, entity, [trait, partial] as ConfigurableTrait);
+    }
+}
+
+export function removeAspect(entity: Entity, aspect: Aspect) {
+    removeTrait(getEntityWorld(entity), entity, ...aspect.traits);
+}
